export function makeNil() { return { type: "nil" }; }
export function makeSymbol(name) { return { type: "symbol", name }; }
export function makeList(value) { return { type: "list", value }; }
export function makeNumber(n) { return { type: "number", value: n }; }
export function makeString(s) { return { type: "string", value: s }; }
export function makeBoolean(b) { return { type: "boolean", value: b }; }
export function makeEnumCase(name) { return { type: "enum-case", name }; }
